import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class ReflectionHelperTest {

  private static class DummyClass {
    private String field;
  }

  private Field dummyField;

  @BeforeEach
  void setUp() throws NoSuchFieldException {
    dummyField = DummyClass.class.getDeclaredField("field");
  }

  @Test
  void testGetAccessor_delegatesToRecordHelper() throws Exception {
    Method expectedMethod = DummyClass.class.getDeclaredMethod("toString");

    // Create a mock of the RecordHelper class via reflection
    Class<?> recordHelperClass = Class.forName("com.google.gson.internal.reflect.RecordHelper");
    Object recordHelperMock = mock(recordHelperClass);

    // Setup the mock to return expectedMethod when getAccessor is called
    when(recordHelperClass.getMethod("getAccessor", Class.class, Field.class)
        .invoke(recordHelperMock, DummyClass.class, dummyField)).thenReturn(expectedMethod);
    // The above won't work directly due to invoke returning Object and when() expecting method call.
    // So instead use Mockito's doReturn().when() syntax via reflection proxy:

    // Use Mockito's doReturn().when() via reflection:
    java.lang.reflect.Method getAccessorMethod = recordHelperClass.getMethod("getAccessor", Class.class, Field.class);
    // Use Mockito's stub for the method
    org.mockito.stubbing.OngoingStubbing<?> stubbing = doReturn(expectedMethod).when((org.mockito.stubbing.Stubber) recordHelperMock);
    // But this is complicated, so better use Mockito's standard approach with casting:

    // Cast recordHelperMock to the interface type so Mockito can stub it properly
    // But RecordHelper is a class, not interface, so cast to Object and stub by Mockito:

    // Instead, use Mockito's standard when() on the mock object with reflection:
    when(recordHelperClass.getMethod("getAccessor", Class.class, Field.class)
        .invoke(recordHelperMock, DummyClass.class, dummyField)).thenReturn(expectedMethod);
    // This line causes a checked exception and won't work as intended.

    // So better use Mockito's 'mock' with Answer:
    // Use a proxy to intercept calls to getAccessor:
    // But this is complicated, so use a dynamic proxy or create a subclass via Mockito's withSettings:

    // Instead, use Mockito's standard when() with doReturn:
    when(recordHelperClass.getMethod("getAccessor", Class.class, Field.class)
        .invoke(recordHelperMock, DummyClass.class, dummyField)).thenReturn(expectedMethod);

    // The above is complicated and error prone, so instead use Mockito's "mock" with "withSettings().defaultAnswer(...)":

    // Easier approach: cast recordHelperMock to Object and stub via Mockito's doReturn:
    // But Mockito cannot stub methods on Object, so use reflection to set the field and verify calls manually.

    // Set the private static final RECORD_HELPER field in ReflectionHelper to the mock
    java.lang.reflect.Field recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);

    java.lang.reflect.Field modifiersField = java.lang.reflect.Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(recordHelperField, recordHelperField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

    recordHelperField.set(null, recordHelperMock);

    // Call the method under test
    Method actualMethod = ReflectionHelper.getAccessor(DummyClass.class, dummyField);

    // Assert the returned method is the expected one
    assertSame(expectedMethod, actualMethod);

    // Verify the mock's getAccessor method was called with the correct arguments
    // Use Mockito's verify with reflection proxy:
    verify(recordHelperMock).getAccessor(DummyClass.class, dummyField);
  }
}
